  $('measureProjectName').textContent=$('projectName').value||'Проект потолка';$('measureCreated').textContent='Сформирован: '+new Date().toLocaleDateString('ru-RU');$('measureClient').textContent=$('clientName').value||'Не указан';$('measureAddress').textContent=$('clientAddress').value||'Не указан';$('measureMaterial').textContent=$('canvasType').selectedOptions[0].text+' · '+$('canvasColor').value;$('measureMetrics').textContent=fmt(t.a)+' м² / '+fmt(t.p)+' м';
  $('measureSideRows').innerHTML=points.map((p,i)=>`<tr><td>${vertexName(i)}–${vertexName((i+1)%points.length)}</td><td>${fmt(dist(p,points[(i+1)%points.length]))} м</td><td>${fmt(interiorAngle(i),1)}°</td></tr>`).join('');
