document.querySelectorAll('[data-object-tool]').forEach(b=>b.onclick=()=>{mode='object:'+b.dataset.objectTool;document.querySelectorAll('[data-object-tool],#selectTool,#addPointTool').forEach(x=>x.classList.remove('active'));b.classList.add('active');$('canvasTip').textContent='Нажмите внутри контура, чтобы разместить объект';});
