var metaBase=objectMeta;
objectMeta=function(type){return {vent:{name:'Вентиляция / люк',color:'#5b8bbd',mark:'▣'},cornice:{name:'Скрытый карниз',color:'#a57943',mark:'⌐'},track:{name:'Трековая точка',color:'#383d52',mark:'═'},separator:{name:'Разделитель полотен',color:'#7b5caa',mark:'║'}}[type]||metaBase(type)};
function renderPreflight(){const t=totals(),items=[];const add=(state,title,detail)=>items.push({state,title,detail});add(points.length>=3?'ok':'error','Контур помещения',points.length>=3?'Контур содержит '+points.length+' вершин.':'Добавьте минимум 3 вершины.');add(!selfIntersects()?'ok':'error','Пересечения линий',selfIntersects()?'Контур пересекается.':'Самопересечений нет.');add(t.a>=1?'ok':'error','Площадь',t.a>=1?fmt(t.a)+' м².':'Площадь слишком мала.');add(angleClosure===null||angleClosure<.03?'ok':'warn','Замыкание по углам',angleClosure===null?'Не проверялось по углам.':angleClosure<.03?'Расхождение в допуске.':'Расхождение '+fmt(angleClosure)+' м.');add(diagonals.length?'ok':'warn','Контрольные диагонали',diagonals.length?'Добавлено: '+diagonals.length+'.':'Для сложного контура добавьте диагонали.');add($('clientName').value?'ok':'warn','Данные клиента',$('clientName').value?'Клиент указан.':'Не заполнено имя клиента.');add($('canvasPrice').value>0&&$('profilePrice').value>0?'ok':'error','Комплектация и цены','Полотно и профиль '+($('canvasPrice').value>0&&$('profilePrice').value>0?'имеют цену.':'требуют цены.'));add(!$('profileType').value?'error':'ok','Тип профиля',$('profileType').value||'Не выбран.');const errors=items.filter(x=>x.state==='error').length,warns=items.filter(x=>x.state==='warn').length;$('preflightSummary').textContent=errors?`Есть ${errors} критических ошибок`:(warns?`Проект готов с ${warns} предупреждениями`:'Проект готов к передаче на производство');$('preflightList').innerHTML=items.map(x=>`<div class="preflight-item ${x.state}"><span class="mark">${x.state==='ok'?'✓':x.state==='warn'?'!':'×'}</span><div><b>${x.title}</b><small>${x.detail}</small></div></div>`).join('');}
