function quotePreset(kind){const map={economy:{canvasType:'mat',canvasPrice:590,profileType:'Стандартный ПВХ',profilePrice:95,installPrice:450,markup:15},standard:{canvasType:'satin',canvasPrice:790,profileType:'Алюминиевый',profilePrice:240,installPrice:550,markup:20},shadow:{canvasType:'mat',canvasPrice:950,profileType:'Теневой',profilePrice:480,installPrice:700,markup:25},light:{canvasType:'translucent',canvasPrice:1150,profileType:'Световая система',profilePrice:900,installPrice:850,markup:25}}[kind];Object.entries(map).forEach(([id,value])=>$(id).value=value);if(kind==='light'){$('lightLine').value=Math.max(2,Math.round(perimeter()/4));}update();toast('Шаблон сметы применён')}
