var PROJECTS_KEY='ceiling-projects', PROJECTS_VERSION=2;
function readProjects(){try{const raw=JSON.parse(localStorage.getItem(PROJECTS_KEY)||'[]');return Array.isArray(raw)?raw:[]}catch{return []}}
function writeProjects(list){localStorage.setItem(PROJECTS_KEY,JSON.stringify(list.slice(0,30)))}
function renderSaved(){const host=$('savedList');if(!host)return;const list=readProjects();host.innerHTML=list.length?list.map((p,i)=>`<div class="saved-item-wrap"><button class="saved-item" data-index="${i}">${p.inputs?.projectName||'Без названия'}<small>${p.saved||p.updated||''}</small></button><button class="saved-delete" data-delete-project="${i}" title="Удалить проект">×</button></div>`).join(''):'<p class="hint">Сохранённых проектов пока нет</p>';host.querySelectorAll('.saved-item').forEach(b=>b.onclick=()=>{apply(list[+b.dataset.index]);toast('Проект открыт')});host.querySelectorAll('[data-delete-project]').forEach(b=>b.onclick=()=>{if(confirm('Удалить этот проект?')){list.splice(+b.dataset.deleteProject,1);writeProjects(list);renderSaved();toast('Проект удалён')}})}
$('saveProject').onclick=()=>{const item=Object.assign(snapshot(),{version:PROJECTS_VERSION,updated:new Date().toLocaleString('ru-RU')});let list=readProjects();const name=(item.inputs.projectName||'Без названия').trim().toLowerCase();const existing=list.findIndex(p=>(p.inputs?.projectName||'Без названия').trim().toLowerCase()===name);if(existing>=0)list.splice(existing,1);list.unshift(item);writeProjects(list);localStorage.removeItem('ceiling-autosave');renderSaved();$('saveState').textContent='✓ Сохранено';toast(existing>=0?'Проект обновлён':'Проект сохранён')};
