// Производственный контроль геометрии и линейных систем.
function lineObjects(){return planObjects.filter(o=>o.x2!==undefined)}
function productionGeometryChecks(){const issues=[];const complex=points.length>6||selfIntersects();if(complex&&!diagonals.length)issues.push({state:'warn',title:'Триангуляция сложного контура',detail:'Для многоугольника добавьте минимум одну контрольную диагональ.'});lineObjects().forEach((o,i)=>{const len=dist(o,{x:o.x2,y:o.y2});if(len<0.2)issues.push({state:'error',title:`Линейный объект ${i+1}`,detail:'Длина линии меньше 0,2 м.'});if(!o.geometryAligned)issues.push({state:'warn',title:`Линейный объект ${i+1}`,detail:'Линия ещё не привязана к геометрии стены.'})});return issues}
var preflightBase=renderPreflight;
renderPreflight=function(){preflightBase();const extra=productionGeometryChecks();if(!extra.length)return;const host=$('preflightList');if(host)host.insertAdjacentHTML('beforeend',extra.map(x=>`<div class="preflight-item ${x.state}"><span class="mark">${x.state==='error'?'×':'!'}</span><div><b>${x.title}</b><small>${x.detail}</small></div></div>`).join(''));};
function roomDiagnostics(){const result=[];if(selfIntersects())result.push({state:'error',title:'Самопересечение контура',detail:'Проверьте порядок вершин и повторите замер.'});points.forEach((p,i)=>{const angle=interiorAngle(i);if(angle<25||angle>335)result.push({state:'warn',title:`Угол ${vertexName(i)}`,detail:`Острый угол ${fmt(angle,1)}°. Нужна контрольная проверка на объекте.`});});for(let i=0;i<points.length;i++){const len=dist(points[i],points[(i+1)%points.length]);if(len<.15)result.push({state:'error',title:`Сторона ${vertexName(i)}–${vertexName((i+1)%points.length)}`,detail:'Сторона короче 0,15 м и требует исправления.'})}return result}
var diagnosticsBase=productionGeometryChecks;
productionGeometryChecks=function(){return [...diagnosticsBase(),...roomDiagnostics()]};
var alignBase=alignLineToRoom;
alignLineToRoom=function(a,b){const aligned=alignBase(a,b);let dx=aligned.x2-aligned.x,dy=aligned.y2-aligned.y,len=Math.hypot(dx,dy)||1;const ux=dx/len,uy=dy/len;for(let i=0;i<points.length;i++){const s=points[i],e=points[(i+1)%points.length],ex=e.x-s.x,ey=e.y-s.y,el=Math.hypot(ex,ey)||1,tx=ex/el,ty=ey/el;if(Math.abs(tx*ux+ty*uy)>.94){const cx=(aligned.x+aligned.x2)/2,cy=(aligned.y+aligned.y2)/2,proj=(cx-s.x)*tx+(cy-s.y)*ty,half=Math.min(len/2,el/2),clamped=Math.max(half,Math.min(el-half,proj));const center={x:s.x+tx*clamped,y:s.y+ty*clamped};return{x:center.x-ux*half,y:center.y-uy*half,x2:center.x+ux*half,y2:center.y+uy*half}}}return aligned};
function suggestTriangulation(){if(points.length<4)return;for(let i=2;i<points.length-1;i++){if(!diagonals.some(d=>(d.from===0&&d.to===i)||(d.from===i&&d.to===0)))diagonals.push({from:0,to:i,length:dist(points[0],points[i])})}renderDiagonals();toast('Контрольные диагонали добавлены по контуру')}
$('suggestDiagonals').onclick=suggestTriangulation;
var managerBase=renderObjectManager;
