var snapEnabled=true,snapStep=.25;function snapValue(v){return Math.round(v/snapStep)*snapStep}function snapPlanObjects(){if(!snapEnabled)return;planObjects.forEach(o=>{o.x=snapValue(o.x);o.y=snapValue(o.y);if(o.x2!==undefined){o.x2=snapValue(o.x2);o.y2=snapValue(o.y2)}});draw();update()}
