function placementChecks(){const issues=[],all=planObjects.filter(o=>o.x2===undefined);all.forEach((o,i)=>{const wallDistance=Math.min(...points.map((p,j)=>{const q=points[(j+1)%points.length],dx=q.x-p.x,dy=q.y-p.y,l2=dx*dx+dy*dy||1,t=Math.max(0,Math.min(1,((o.x-p.x)*dx+(o.y-p.y)*dy)/l2));return Math.hypot(o.x-(p.x+t*dx),o.y-(p.y+t*dy))}));if(wallDistance<.15)issues.push({state:'warn',title:`Элемент ${i+1} близко к стене`,detail:`Расстояние ${fmt(wallDistance)} м. Проверьте монтажный отступ.`});for(let j=i+1;j<all.length;j++)if(Math.hypot(o.x-all[j].x,o.y-all[j].y)<.25)issues.push({state:'warn',title:'Слишком близкое размещение',detail:'Между элементами меньше 0,25 м.'})});return issues}
